22	
23	#ifndef CUDAQ_DISABLE_JIT_COMPILER
24	namespace cudaq_internal::compiler {
25	cudaq::CompiledModule
26	compileModule(std::unique_ptr<cudaq::CompileTarget> target,
27	              const cudaq::SourceModule &src, cudaq::KernelArgs args,
28	              bool isEntryPoint = true);
29	} // namespace cudaq_internal::compiler
30	#endif
31	
32	namespace cudaq {
33	namespace detail {
34	
35	/// @brief Execute the given function within the given execution context.
36	template <typename Policy, typename Callable, typename... Args>
37	auto launch(const Policy &policy, std::size_t qpu_id, ExecutionContext &ctx,
38	            quantum_platform &platform, Callable &&f, Args &&...args)
39	    -> Policy::result_type {
40	
41	  // Python builds without CUDAQ_LIBRARY_MODE defined, so we need to check for
42	  // it at runtime
43	  bool library_mode = platform.is_library_mode();
44	#ifdef CUDAQ_LIBRARY_MODE
45	  library_mode = true;
46	#endif
47	  if (library_mode) {
48	    // async_policy (async_policy_wrapper) + library mode is unreachable:
49	    if constexpr (requires { policy.inner; })
50	      throw std::logic_error("async policy must not reach library-mode path");
51	    else {
52	      CUDAQ_INFO("Launching kernel in library mode with policy {}",
53	                 policy.name);
54	      return detail::with_policy_and_ctx(policy, ctx, [&]() {
55	        return cudaq::ExecutionManager::with_default_em(
56	            policy, [&]() { f(std::forward<Args>(args)...); });
57	      });
58	    }
59	  }
60	
61	  typename Policy::result_type result;
62	  auto &qpu = platform.getQPU(qpu_id);
63	  ctx.executeKernelApi = [&qpu, &result, &policy](const AnyModule &module,
64	                                                  const KernelArgs &args) {
65	    CompiledModule compiled;
66	    if (const auto *source = std::get_if<SourceModule>(&module)) {
67	#ifdef CUDAQ_DISABLE_JIT_COMPILER
68	      // If JIT compilation is disabled, compilation is a no-op. QPUs may throw
69	      // an error if they expect a JIT-compiled module.
70	      CUDAQ_INFO("JIT compilation is disabled. Compilation is a no-op.");
71	      compiled = CompiledModule{*source};
72	#else
73	      CUDAQ_INFO("No compiled module found. Compiling.");
74	      std::unique_ptr<cudaq::CompileTarget> target;
75	      if constexpr (requires { policy.inner; }) {
76	        target = cudaq::get_compile_target(policy.inner);
77	      } else {
78	        target = cudaq::get_compile_target(policy);
79	      }
80	      compiled = cudaq_internal::compiler::compileModule(std::move(target),
81	                                                         *source, args);
82	#endif
83	    } else {
84	      CUDAQ_INFO("Found compiled module. Skipping compilation.");
85	      compiled = std::get<CompiledModule>(module);
86	    }
87	    CUDAQ_INFO("Launching kernel.");
88	    result = qpu.launchKernel(policy, compiled, args);
89	  };
90	
91	  if constexpr (requires { policy.inner; })
92	    CUDAQ_INFO("Launching kernel in async mode with policy {}",
93	               policy.inner.name);
94	  else
95	    CUDAQ_INFO("Launching kernel in sync mode with policy {}", policy.name);
96	
97	  detail::try_finally(
98	      [&] {
99	        detail::with_policy_and_ctx(policy, ctx, std::forward<Callable>(f),
100	                                    std::forward<Args>(args)...);
101	      },
102	      [&] { ctx.executeKernelApi = nullptr; });
103	  return result;
104	}
105	} // namespace detail
106	} // namespace cudaq
