8	
9	#pragma once
10	
11	#include "common/ExecutionContext.h"
12	#include "common/SampleResult.h"
13	#include "cudaq/algorithms/broadcast.h"
14	#include "cudaq/algorithms/launch.h"
15	#include "cudaq/algorithms/sample/options.h"
16	#include "cudaq/algorithms/sample/policy.h"
17	#include "cudaq/concepts.h"
18	#include "cudaq/host_config.h"
19	#include "cudaq/platform.h"
20	
21	namespace cudaq {
22	bool kernelHasConditionalFeedback(const std::string &);
23	namespace detail {
24	bool isKernelGenerated(const std::string &);
25	
26	/// @brief Check whether a kernel uses conditional feedback (measurement-
27	/// dependent branching). Checks MLIR metadata first, then optionally checks
28	/// the ExecutionContext's registerNames (populated during library-mode
29	/// tracing).
30	///
31	/// @param kernelName Name of the kernel (for MLIR registry lookup)
32	/// @param ctx Optional pointer to an ExecutionContext populated after tracing
33	/// @return true if conditional feedback is detected
34	inline bool hasConditionalFeedback(const std::string &kernelName,
35	                                   const ExecutionContext *ctx = nullptr) {
36	  if (cudaq::kernelHasConditionalFeedback(kernelName))
37	    return true;
38	  if (ctx && !ctx->registerNames.empty())
39	    return true;
40	  return false;
41	}
42	} // namespace detail
43	
44	/// @brief Define a combined sample function validation concept.
45	/// These concepts provide much better error messages than old-school SFINAE
46	template <typename QuantumKernel, typename... Args>
47	concept SampleCallValid =
48	    ValidArgumentsPassed<QuantumKernel, Args...> &&
49	    HasVoidReturnType<std::invoke_result_t<QuantumKernel, Args...>>;
50	
51	namespace detail {
52	
53	/// @brief Validate sampling arguments, populate the given execution context
54	/// and sample policy, and (in library mode) trace the kernel to detect any
55	/// mid-circuit conditional feedback.
56	/// @param ctx The execution context to populate (must already be constructed
57	/// with name "sample").
58	/// @param policy The sample policy to populate.
59	template <typename KernelFunctor>
60	void samplePreamble(ExecutionContext &ctx, sample_policy &policy,
61	                    KernelFunctor &&wrappedKernel, quantum_platform &platform,
62	                    const std::string &kernelName, int shots,
63	                    bool explicitMeasurements, std::size_t qpu_id,
64	                    std::size_t batchIteration = 0,
65	                    std::size_t totalBatchIters = 0) {
66	  if (cudaq::detail::hasConditionalFeedback(kernelName))
67	    throw std::runtime_error(
68	        "`cudaq::sample` and `cudaq::sample_async` no longer support kernels "
69	        "that branch on measurement results. Kernel '" +
70	        kernelName +
71	        "' uses conditional feedback. Use `cudaq::run` or `cudaq::run_async` "
72	        "instead. See CUDA-Q documentation for migration guide.");
73	
74	  if (explicitMeasurements && !platform.supports_explicit_measurements())
75	    throw std::runtime_error("The sampling option `explicit_measurements` is "
76	                             "not supported on this target.");
77	
78	  ctx.kernelName = kernelName;
79	  ctx.batchIteration = batchIteration;
80	  ctx.totalIterations = totalBatchIters;
81	  ctx.explicitMeasurements = explicitMeasurements;
82	
83	  policy.kernelName = kernelName;
84	  policy.options.shots = shots;
85	  policy.options.explicit_measurements = explicitMeasurements;
86	  policy.noiseModel = platform.get_noise(qpu_id);
87	
88	  // For now the noise model has to be duplicated on the policy unfortunately.
89	  // get_noise() still expects it on the execution context.
90	  // TODO: Store the noise on the platform or QPU instead.
91	  ctx.noiseModel = policy.noiseModel;
92	
93	#ifdef CUDAQ_LIBRARY_MODE
94	  // If we have a kernel that has its quake code registered, we
95	  // won't check for if statements with the tracer.
96	  auto isRegistered = detail::isKernelGenerated(kernelName);
97	
98	  // One extra check to see if we have mid-circuit
99	  // measures in library mode
100	  if (!isRegistered && !ctx.hasConditionalsOnMeasureResults) {
101	    // Trace the kernel function
102	    ExecutionContext context("tracer");
103	    context.qpuId = qpu_id;
104	    auto &platform = get_platform();
105	    platform.with_execution_context(context,
106	                                    std::forward<KernelFunctor>(wrappedKernel));
107	    // In trace mode, if we have a measure result
108	    // that is passed to an if statement, then
109	    // we'll have collected registernames
110	    if (!context.registerNames.empty()) {
111	      // append new register names to the main sample context
112	      for (std::size_t i = 0; i < context.registerNames.size(); ++i)
113	        ctx.registerNames.emplace_back("auto_register_" + std::to_string(i));
114	
115	      ctx.hasConditionalsOnMeasureResults = true;
116	    }
117	  }
118	#endif
119	}
120	
121	template <typename KernelFunctor>
122	auto runSamplingAsync(KernelFunctor &&wrappedKernel, quantum_platform &platform,
123	                      const std::string &kernelName, int shots,
124	                      bool explicitMeasurements = false, std::size_t qpu_id = 0,
125	                      std::optional<noise_model> noise = std::nullopt);
126	
127	/// @brief Take the input KernelFunctor (a lambda that captures runtime
128	/// arguments and invokes the quantum kernel) and invoke the sampling process.
129	template <typename KernelFunctor>
130	sample_result
131	runSampling(KernelFunctor &&wrappedKernel, quantum_platform &platform,
132	            const std::string &kernelName, int shots, bool explicitMeasurements,
133	            std::size_t qpu_id = 0, std::size_t batchIteration = 0,
134	            std::size_t totalBatchIters = 0) {
135	
136	  if (platform.is_remote(qpu_id)) {
137	    auto noise = platform.get_noise(qpu_id);
138	    std::optional<noise_model> noise_opt =
139	        noise ? std::make_optional(*noise) : std::nullopt;
140	    auto result = runSamplingAsync(wrappedKernel, platform, kernelName, shots,
141	                                   explicitMeasurements, qpu_id, noise_opt);
142	    return result.get();
143	  }
144	
145	  // Create the execution context.
146	  ExecutionContext ctx("sample", shots, qpu_id);
147	  sample_policy policy;
148	  samplePreamble(ctx, policy, std::forward<KernelFunctor>(wrappedKernel),
149	                 platform, kernelName, shots, explicitMeasurements, qpu_id,
150	                 batchIteration, totalBatchIters);
151	
152	  auto isQuantumDevice = platform.is_emulated(qpu_id);
153	
154	  // Loop until all shots are returned.
155	  cudaq::sample_result counts;
156	
157	  while (counts.get_total_shots() < static_cast<std::size_t>(shots)) {
158	    auto result = detail::launch(policy, qpu_id, ctx, platform,
159	                                 std::forward<KernelFunctor>(wrappedKernel));
160	
161	    // If target is hardware backend, need to launch only once, hence exit
162	    // early
163	    if (isQuantumDevice)
164	      return result;
165	
166	    if (counts.get_total_shots() == 0)
167	      counts = std::move(result); // optimize for first iteration
168	    else
169	      counts += result;
170	
171	    if (counts.get_total_shots() == 0) {
172	      if (explicitMeasurements)
173	        throw std::runtime_error(
174	            "The sampling option `explicit_measurements` is not supported on "
175	            "a kernel without any measurement operation.");
176	      printf("WARNING: this kernel invocation produced 0 shots worth "
177	             "of results when executed. Exiting shot loop to avoid "
178	             "infinite loop.");
179	      break;
180	    }
181	  }
182	  return counts;
183	}
184	
185	/// @brief Take the input KernelFunctor (a lambda that captures runtime
186	/// arguments and invokes the quantum kernel) and invoke the sampling process
187	/// asynchronously. Return an `async_sample_result`, clients can retrieve the
188	/// results at a later time via the `get()` call.
189	///
190	/// @param wrappedKernel The kernel functor to execute.
191	/// @param platform The quantum platform to use.
192	/// @param kernelName The name of the kernel.
193	/// @param shots The number of shots to run.
194	/// @param explicitMeasurements Whether to use explicit measurements.
195	/// @param qpu_id The QPU ID to use.
196	/// @param noise The optional noise model to apply during execution. The noise
197	///              model is copied into the asynchronous task to ensure proper
198	///              lifetime.
199	template <typename KernelFunctor>
200	auto runSamplingAsync(KernelFunctor &&wrappedKernel, quantum_platform &platform,
201	                      const std::string &kernelName, int shots,
202	                      bool explicitMeasurements, std::size_t qpu_id,
203	                      std::optional<noise_model> noise) {
204	  if (qpu_id >= platform.num_qpus()) {
205	    throw std::invalid_argument("Provided qpu_id " + std::to_string(qpu_id) +
206	                                " is invalid (must be < " +
207	                                std::to_string(platform.num_qpus()) +
208	                                " i.e. platform.num_qpus())");
209	  }
210	
211	#ifndef CUDAQ_LIBRARY_MODE
212	  // Treat an empty noise model as "no noise".
213	  const bool hasNoise = noise.has_value() && !noise->empty();
214	  // If we are remote, then create the sampling executor with `cudaq::future`
215	  // provided. Note: noise model is not supported on remote platforms.
216	  if (platform.is_remote(qpu_id)) {
217	    if (hasNoise)
218	      throw std::runtime_error(
219	          "Noise model is not supported on remote platforms.");
220	
221	    // Create the execution context.
222	    ExecutionContext ctx("sample", shots, qpu_id);
223	    async_sample_policy async_policy;
224	    samplePreamble(ctx, async_policy.inner,
225	                   std::forward<KernelFunctor>(wrappedKernel), platform,
226	                   kernelName, shots, explicitMeasurements, qpu_id);
227	    return detail::launch(async_policy, qpu_id, ctx, platform,
228	                          std::forward<KernelFunctor>(wrappedKernel));
229	  }
230	#endif
231	
232	  KernelExecutionTask task(
233	      [qpu_id, explicitMeasurements, shots, kernelName, &platform,
234	       noise = std::move(noise),
235	       kernel = std::forward<KernelFunctor>(wrappedKernel)]() mutable {
236	        const bool hasNoise = noise.has_value() && !noise->empty();
237	
238	        // Set noise model before execution if provided.
239	        if (hasNoise)
240	          platform.set_noise(&noise.value(), qpu_id);
241	
242	        sample_result result;
243	        try {
244	          result = detail::runSampling(kernel, platform, kernelName, shots,
245	                                       explicitMeasurements, qpu_id);
246	        } catch (...) {
247	          // Ensure noise model is reset even on exception.
248	          if (hasNoise)
249	            platform.reset_noise(qpu_id);
250	          throw;
251	        }
252	
253	        // Reset noise model after execution.
254	        if (hasNoise)
255	          platform.reset_noise(qpu_id);
256	
257	        return result;
258	      });
259	
260	  return async_sample_result(
261	      detail::future(platform.enqueueAsyncTask(qpu_id, task)));
262	}
263	} // namespace detail
264	
265	/// @overload
266	/// @brief Sample the given quantum kernel expression and return the
267	/// mapping of observed bit strings to corresponding number of
268	/// times observed.
269	///
270	/// @param kernel the kernel expression, must contain final measurements
271	/// @param args the variadic concrete arguments for evaluation of the kernel.
272	/// @returns counts, The counts dictionary.
273	///
274	/// @details Given a quantum kernel with void return type, sample
275	///          the corresponding quantum circuit generated by the kernel
276	///          expression, returning the mapping of bits observed to number
277	///          of times it was observed.
278	template <typename QuantumKernel, typename... Args>
279	  requires SampleCallValid<QuantumKernel, Args...>
