139	  async_result &operator=(async_result &&other) = default;
140	
141	  /// @brief Return the asynchronously computed data, will
142	  /// wait until the data is ready.
143	  T get() {
144	    auto data = result.get();
145	
146	    if constexpr (std::is_same_v<T, sample_result>)
147	      return data;
148	
149	    if constexpr (std::is_same_v<T, observe_result>) {
150	      if (!spinOp)
151	        throw std::runtime_error(
152	            "Returning an observe_result requires a spin_op.");
153	
154	      auto checkRegName = spinOp->to_string();
155	      if (data.has_expectation(checkRegName))
156	        return observe_result(data.expectation(checkRegName), *spinOp, data);
157	
158	      // this assumes we ran in shots mode.
159	      double sum = 0.0;
160	      for (const auto &term : spinOp.value()) {
161	        if (term.is_identity())
162	          // FIXME: simply taking real here is very unclean at best,
163	          // and might be wrong/hiding a user error that should cause a failure
164	          // at worst. It would be good to not store a general spin op for the
165	          // result, but instead store the term ids and the evaluated
166	          // (double-valued) coefficient. Similarly, evaluate would fail if
167	          // the operator was parameterized. In general, both parameters, and
168	          // complex coefficients are valid for a spin-op term.
169	          // The code here (and in all other places that do something similar)
170	          // will work perfectly fine as long as there is no user error, but
171	          // the passed observable should really be validated properly and not
172	          // processed here as is making assumptions about correctness.
173	          sum += term.evaluate_coefficient().real();
174	        else
175	          sum += data.expectation(term.get_term_id()) *
176	                 term.evaluate_coefficient().real();
177	      }
178	      return observe_result(sum, *spinOp, data);
179	    }
180	
181	    return T();
182	  }
183	
184	  template <typename U>
185	  friend std::ostream &operator<<(std::ostream &, async_result<U> &);
186	
187	  template <typename U>
